import React, { useEffect } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { fetchNotifications, markNotificationRead, markAllRead } from '../redux/thunks/notificationThunks';
import { NODE_API } from '../api/config';
import './Notifications.css';

const NOTIF_ICONS = {
  Friend_Request_Send: '👋',
  Friend_Request_Accepted: '🤝',
  Friend_Request_Rejected: '😔',
  New_Message_Send: '💬',
  USER_COMMENT_POST: '💭',
  USER_LIKE_POST: '❤️',
  GROUP_ADMIN_ADD_MEMBER: '👥',
};

const Notifications = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { notifications, loading, unreadCount, hasMore } = useSelector((state) => state.notifications);

  useEffect(() => {
    dispatch(fetchNotifications({ skip: 0, limit: 30 }));
  }, [dispatch]);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const handleMarkAllRead = () => {
    dispatch(markAllRead());
  };

  const handleLoadMore = () => {
    if (!loading && hasMore) {
      dispatch(fetchNotifications({ skip: notifications.length, limit: 30 }));
    }
  };

  const handleNotificationClick = (notif) => {
    if (!notif.isRead) {
      dispatch(markNotificationRead({ notificationId: notif._id }));
    }
    if (notif.notificationType?.includes('Friend_Request')) {
      navigate('/friends');
    } else if (notif.notificationType?.includes('Message')) {
      navigate('/messages');
    } else if (notif.notificationType?.includes('COMMENT') || notif.notificationType?.includes('LIKE')) {
      navigate('/');
    } else if (notif.notificationType?.includes('GROUP')) {
      navigate('/groups');
    }
  };

  const timeAgo = (dateStr) => {
    if (!dateStr) return '';
    const diff = Date.now() - new Date(dateStr).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return 'Just now';
    if (mins < 60) return `${mins}m ago`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h ago`;
    const days = Math.floor(hrs / 24);
    if (days < 7) return `${days}d ago`;
    return new Date(dateStr).toLocaleDateString();
  };

  return (
    <div className="notifications-page">
      <div className="notifications-header">
        <h1 className="notifications-title">
          Notifications
          {unreadCount > 0 && <span className="notifications-unread-badge">{unreadCount}</span>}
        </h1>
        {unreadCount > 0 && (
          <button className="notifications-mark-all" onClick={handleMarkAllRead}>
            Mark all read
          </button>
        )}
      </div>

      <div className="notifications-list">
        {loading && notifications.length === 0 && (
          <div className="groups-loading"><div className="page-loading-spinner" /></div>
        )}
        {!loading && notifications.length === 0 && (
          <div className="groups-empty"><p>No notifications</p></div>
        )}

        {notifications.map((notif) => {
          const senderId = notif.senderId || '';
          const avatar = null; // senderId is just an ID string, no image available
          const name = senderId || 'Someone';
          const icon = NOTIF_ICONS[notif.notificationType] || '🔔';

          return (
            <div
              key={notif._id}
              className={`notification-item ${!notif.isRead ? 'unread' : ''}`}
              onClick={() => handleNotificationClick(notif)}
            >
              <div className="notification-avatar-wrap">
                {avatar ? (
                  <img src={avatar} alt="" className="notification-avatar" />
                ) : (
                  <div className="notification-avatar-placeholder">
                    {name[0].toUpperCase()}
                  </div>
                )}
                <span className="notification-type-icon">{icon}</span>
              </div>
              <div className="notification-content">
                <p className="notification-text">
                  <strong>{name}</strong> {notif.textMessage || 'sent you a notification'}
                </p>
                <span className="notification-time">{timeAgo(notif.createdAt)}</span>
              </div>
              <span className="notification-arrow">→</span>
            </div>
          );
        })}

        {hasMore && notifications.length > 0 && (
          <button className="home-load-more" onClick={handleLoadMore} disabled={loading}>
            {loading ? 'Loading...' : 'Load More'}
          </button>
        )}
      </div>
    </div>
  );
};

export default Notifications;
